// Mock enrichment — simulates Apollo.io response per record
// Replace this node with real Apollo HTTP Request node in production
// On failure: flags record for dead letter queue

const industryProfiles = {
  'Finance': {
    techStack: ['SAP', 'Oracle', 'NetSuite'],
    painPoints: 'High invoice volume, manual AP processes, overbilling risk from vendors',
    buyerContext: 'Finance teams under pressure to reduce costs and improve accuracy'
  },
  'Logistics': {
    techStack: ['Oracle TMS', 'SAP', 'custom ERP'],
    painPoints: 'Complex freight invoicing, carrier overbilling, rate card compliance issues',
    buyerContext: 'Operations teams dealing with thousands of freight invoices monthly'
  },
  'Retail': {
    techStack: ['NetSuite', 'QuickBooks', 'Microsoft Dynamics'],
    painPoints: 'Thousands of supplier invoices, duplicate payments, vendor disputes',
    buyerContext: 'AP teams overwhelmed with high volume, error-prone manual matching'
  },
  'Healthcare': {
    techStack: ['Epic', 'Oracle', 'SAP'],
    painPoints: 'Regulatory compliance on payments, complex billing environments, audit trails',
    buyerContext: 'Finance teams needing accuracy and compliance in vendor payments'
  },
  'Manufacturing': {
    techStack: ['SAP', 'Oracle', 'Microsoft Dynamics'],
    painPoints: 'Multi-supplier complexity, PO matching at scale, budget overruns',
    buyerContext: 'Procurement and finance teams managing large supplier networks'
  }
};

const items = $input.all();
const enriched = [];

for (const item of items) {
  try {
    const fields = item.json.fields || item.json;
    const industry = fields['Industry'] || 'Finance';
    const profile = industryProfiles[industry] || industryProfiles['Finance'];

    // Validate minimum required fields
    if (!fields['Company Name'] || !fields['Email']) {
      throw new Error(`Missing required fields: Company Name or Email`);
    }

    enriched.push({
      json: {
        record_id: item.json.id,
        company_name: fields['Company Name'],
        industry: industry,
        employee_count: fields['Employee Count'] || 0,
        annual_revenue: fields['Annual Revenue'] || 'Unknown',
        contact_name: fields['Contact Name'] || 'Unknown',
        contact_title: fields['Contact Title'] || 'Unknown',
        email: fields['Email'],
        date_added: fields['Date Added'],
        enriched_tech_stack: profile.techStack.join(', '),
        enriched_pain_points: profile.painPoints,
        enriched_buyer_context: profile.buyerContext,
        enrichment_source: 'Mock-Apollo',
        enrichment_status: 'Success'
      }
    });
  } catch (err) {
    // Flag failed records — routed to dead letter queue downstream
    enriched.push({
      json: {
        record_id: item.json.id || 'unknown',
        company_name: (item.json.fields || item.json)['Company Name'] || 'Unknown',
        enrichment_status: 'failed',
        failed_at: 'Enrichment',
        error_message: err.message,
        processed_at: new Date().toISOString()
      }
    });
  }
}

return enriched;

// Deterministic fit scoring for OpenEnvoy ICP
const items = $input.all();
const scored = [];

for (const item of items) {
  const data = item.json;
  let score = 0;
  const reasons = [];

  // Employee count
  const employees = data.employee_count || 0;
  if (employees >= 500) {
    score += 3;
    reasons.push('Enterprise size (500+ employees) — high invoice volume likely');
  } else if (employees >= 100) {
    score += 2;
    reasons.push('Mid-market size (100-499 employees) — good fit range');
  } else if (employees >= 50) {
    score += 1;
    reasons.push('SMB (50-99 employees) — marginal fit');
  } else {
    reasons.push('Too small (<50 employees) — low invoice volume expected');
  }

  // Industry
  const highFit = ['Logistics', 'Manufacturing', 'Retail', 'Healthcare'];
  const medFit = ['Finance', 'Construction', 'Energy'];
  if (highFit.includes(data.industry)) {
    score += 3;
    reasons.push(`${data.industry} — high invoice volume industry, strong OpenEnvoy fit`);
  } else if (medFit.includes(data.industry)) {
    score += 2;
    reasons.push(`${data.industry} — moderate invoice complexity, good fit`);
  } else {
    score += 1;
    reasons.push(`${data.industry} — industry fit unclear, needs qualification`);
  }

  // Revenue
  const revenue = data.annual_revenue || '';
  if (revenue.includes('$100M') || revenue.includes('$500M') || revenue.includes('$1B')) {
    score += 3;
    reasons.push('Large revenue — significant AP spend, ROI case strong');
  } else if (revenue.includes('$10M') || revenue.includes('$50M')) {
    score += 2;
    reasons.push('Mid-range revenue — viable AP automation candidate');
  } else {
    score += 1;
    reasons.push('Revenue unknown or low — ROI case needs validation');
  }

  // Contact title
  const title = (data.contact_title || '').toLowerCase();
  if (title.includes('cfo') || title.includes('chief financial') || title.includes('vp finance')) {
    score += 1;
    reasons.push('Economic buyer contact (CFO/VP Finance) — decision maker access');
  } else if (title.includes('ap manager') || title.includes('accounts payable') || title.includes('controller')) {
    score += 1;
    reasons.push('AP practitioner contact — end user, champion potential');
  }

  const tier = score >= 8 ? 'High' : score >= 5 ? 'Medium' : 'Low';

  scored.push({
    json: {
      ...data,
      fit_score: score,
      fit_tier: tier,
      scoring_reasons: reasons.join(' | ')
    }
  });
}

return scored;

// Parse Claude HTTP API response — with full error handling
// Mode: runOnceForAllItems — n8n passes all items at once

const item = $input.item;
const claudeText = item.json?.content?.[0]?.text || '';
const prospectData = $('Filter Low Fit').item.json;

if (!claudeText || claudeText.trim() === '') {
  throw new Error('Claude returned empty response');
}

let emailDraft;
try {
  const cleaned = claudeText.replace(/```json|```/g, '').trim();
  emailDraft = JSON.parse(cleaned);
} catch (parseErr) {
  const match = claudeText.match(/\{[\s\S]*\}/);
  if (match) {
    emailDraft = JSON.parse(match[0]);
  } else {
    emailDraft = {
      subject: '[AUTO-PARSE FAILED — Review Required]',
      body: claudeText,
      personalization_hook: 'JSON parse failed — raw Claude output saved'
    };
  }
}

if (!emailDraft.subject || !emailDraft.body) {
  throw new Error('Claude response missing required fields: subject or body');
}

return {
  json: {
    ...prospectData,
    email_subject: emailDraft.subject,
    email_body: emailDraft.body,
    personalization_hook: emailDraft.personalization_hook || 'N/A',
    ai_draft_status: 'success',
    processed_at: new Date().toISOString()
  }
};

// Aggregate all items from all paths into a single batch summary
// Counts by actual Status field written to Outbound Queue
// This node receives merged output from all branches

const items = $input.all();

let drafted = 0;
let lowFit = 0;
let aiErrors = 0;
let enrichmentErrors = 0;
let queueWriteErrors = 0;
let watermarkErrors = 0;
let total = items.length;

for (const item of items) {
  const status = item.json.ai_draft_status || '';
  const failedAt = item.json.failed_at || '';
  const fitTier = item.json.fit_tier || '';
  const enrichStatus = item.json.enrichment_status || '';

  if (enrichStatus === 'failed') enrichmentErrors++;
  else if (fitTier === 'Low') lowFit++;
  else if (status === 'failed') aiErrors++;
  else if (status === 'success') drafted++;
  else queueWriteErrors++;
}

const hasErrors = (aiErrors + enrichmentErrors + queueWriteErrors + watermarkErrors) > 0;

return [{
  json: {
    total,
    drafted,
    lowFit,
    aiErrors,
    enrichmentErrors,
    queueWriteErrors,
    hasErrors,
    timestamp: new Date().toISOString()
  }
}];

